code.C:
#include <stdio.h>

int main() {
    int arr[5] = {1, 2, 3, 4, 5};

    // Print the elements of the array
    for (int i = 0; i < 5; i++) {
        printf("%d ", arr[i]);
    }
    printf("\n");

    return 0;
}

code.C++:
#include <iostream>
using namespace std;

int main() {
    int arr[5] = {1, 2, 3, 4, 5};

    // Print the elements of the array
    for (int i = 0; i < 5; i++) {
        cout << arr[i] << " ";
    }
    cout << endl;

    return 0;
}

code.Java:
public class Main {
